// // This module implements an 8-bit shift register that shifts left on the positive edge of the clock and loads the parallel input when the load signal is deasserted.
module shift_register_8bit(
    input clk,
    input load,
    input [7:0] parallel_in,
    output reg [7:0] q
);

always @(posedge clk)
    if (load)
        q <= parallel_in; // Load parallel input
    else
        q <= {1'b0, q[7:1]}; // Shift right

endmodule
